package com.samudhra.certificates.entity;
import jakarta.persistence.*; import java.time.LocalDate;
@Entity @Table(name="students", indexes={@Index(columnList="organization_id"),@Index(columnList="registerNumber")}, uniqueConstraints=@UniqueConstraint(columnNames={"organization_id","registerNumber"})) public class Student extends BaseEntity {
  @ManyToOne(fetch=FetchType.LAZY, optional=false) private Organization organization; @Column(nullable=false) private String name; @Column(nullable=false) private String registerNumber; private String studentType; private String college; private String department; private String course; private String email; private String phone; private String internshipTitle; private String duration; private LocalDate startDate; private LocalDate endDate; private String status="ACTIVE"; private String photoUrl;
  public Organization getOrganization(){return organization;} public void setOrganization(Organization v){organization=v;} public String getName(){return name;} public void setName(String v){name=v;} public String getRegisterNumber(){return registerNumber;} public void setRegisterNumber(String v){registerNumber=v;} public String getStudentType(){return studentType;} public void setStudentType(String v){studentType=v;} public String getCollege(){return college;} public void setCollege(String v){college=v;} public String getDepartment(){return department;} public void setDepartment(String v){department=v;} public String getCourse(){return course;} public void setCourse(String v){course=v;} public String getEmail(){return email;} public void setEmail(String v){email=v;} public String getPhone(){return phone;} public void setPhone(String v){phone=v;} public String getInternshipTitle(){return internshipTitle;} public void setInternshipTitle(String v){internshipTitle=v;} public String getDuration(){return duration;} public void setDuration(String v){duration=v;} public LocalDate getStartDate(){return startDate;} public void setStartDate(LocalDate v){startDate=v;} public LocalDate getEndDate(){return endDate;} public void setEndDate(LocalDate v){endDate=v;} public String getStatus(){return status;} public void setStatus(String v){status=v;} public String getPhotoUrl(){return photoUrl;} public void setPhotoUrl(String v){photoUrl=v;}
}
